import boto3

def az_name_to_id(region: str) -> dict[str, str]:
    """Return {az_name: az_id} for every AZ in the region."""
    ec2 = boto3.client('ec2', region_name=region)
    azs = ec2.describe_availability_zones(
        Filters=[{'Name': 'state', 'Values': ['available']}]
    )['AvailabilityZones']
    return {az['ZoneName']: az['ZoneId'] for az in azs}

def az_id_to_name(region: str) -> dict[str, str]:
    """Return {az_id: az_name} for every AZ in the region."""
    return {v: k for k, v in az_name_to_id(region).items()}

# Example usage
mapping = az_name_to_id('us-east-1')
for name, az_id in sorted(mapping.items()):
    print(f'{name} -> {az_id}')

# Reverse lookup: given a stable AZ ID, find the local name
local_name = az_id_to_name('us-east-1').get('use1-az4', 'unknown')
print(f'use1-az4 is called {local_name!r} in this account')

# Terraform: look up the AZ name for a given AZ ID at plan time
data "aws_availability_zone" "az4" {
  zone_id = "use1-az4"
}

data "aws_availability_zone" "az6" {
  zone_id = "use1-az6"
}

resource "aws_subnet" "app_az4" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.10.0/24"
  availability_zone = data.aws_availability_zone.az4.name  # resolves per-account
  tags = {
    Name  = "app-${data.aws_availability_zone.az4.zone_id}"
    AZ_ID = data.aws_availability_zone.az4.zone_id
  }
}

resource "aws_subnet" "app_az6" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.11.0/24"
  availability_zone = data.aws_availability_zone.az6.name  # resolves per-account
  tags = {
    Name  = "app-${data.aws_availability_zone.az6.zone_id}"
    AZ_ID = data.aws_availability_zone.az6.zone_id
  }
}
# Both subnets land in the same physical AZs in every account this code runs in
